1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	const FIRST_INSURANCE_SURCHARGE = 0.1;
26	const PROCESSING_FEE = 5;
27	
28	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
29	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
30	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
31	
32	const quotePremium = (items: Item[]): number => {
33	  const itemsPremium = items.reduce(
34	    (sum, item) => sum + BASE_PREMIUM[item.type] * (1 + FIRST_INSURANCE_SURCHARGE),
35	    0
36	  );
37	  return roundPremiumUp(itemsPremium + PROCESSING_FEE);
38	};
39	
40	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
41	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
42	  return { results };
43	};
